import { callApi, API } from './authApi';

// Wrapper tiện dụng cho STATIONS API
export const stationApi = {
  // GET /stations/address?page=1&page_size=100
  getAll: (page = 1, page_size = 100) =>
    callApi(API.STATIONS.getAll(page, page_size)),

  // GET /stations/address/{station_id}
  getById: (station_id) =>
    callApi(API.STATIONS.getById(station_id)),

  // POST /stations/address
  create: (body) =>
    callApi(API.STATIONS.create(), body),

  // PUT /stations/address/{station_id}
  update: (station_id, body) =>
    callApi(API.STATIONS.update(station_id), body),

  // DELETE /stations/address/{station_id}
  delete: (station_id) =>
    callApi(API.STATIONS.delete(station_id)),
};
